"""
title: Engagement Intelligence - Precedent Planning
author: WidgeTDC Platform
date: 2026-04-05
version: 1.0.0
license: MIT
description: First-class consulting engagement planning with precedent matching, smart gates, and outcome-driven Q-learning. Calls the orchestrator engagement_* tools via /api/tools REST. Renders rich markdown with grade emojis, similarity bars, phase Gantt. Follows StitchLive v5.2.0 pattern (aiohttp, TTL cache, retry, progress events, DATA_BELOW envelope).
requirements: aiohttp
"""

from pydantic import BaseModel, Field
import aiohttp
import asyncio
import json
import logging
import time
from datetime import datetime, timezone

logger = logging.getLogger(__name__)

GRADE_EMOJI = {
    "exceeded": "\U0001f3c6",
    "met": "\u2705",
    "partial": "\u26a0\ufe0f",
    "missed": "\u274c",
}

SEV_EMOJI = {"high": "\U0001f534", "medium": "\U0001f7e0", "low": "\U0001f7e2"}


def fmt_num(n):
    if n is None:
        return "0"
    try:
        n = float(str(n).replace(",", "")) if isinstance(n, str) else float(n)
    except Exception:
        return str(n)
    if n < 0:
        return "-" + fmt_num(-n)
    if n < 1000:
        return str(int(n)) if n == int(n) else f"{n:.1f}"
    for lim, sfx in [(1e3, "K"), (1e6, "M"), (1e9, "B"), (1e12, "T")]:
        if n < lim * 1000:
            return f"{n/lim:.1f}{sfx}"
    return f"{n/1e12:.1f}T"


def similarity_bar(score, width=10):
    score = max(0.0, min(1.0, float(score)))
    filled = int(round(score * width))
    return "\u2588" * filled + "\u2591" * (width - filled)


def confidence_gauge(conf, width=15):
    conf = max(0.0, min(1.0, float(conf)))
    filled = int(round(conf * width))
    full_char = "\u2588"
    empty_char = "\u2591"
    bar = full_char * filled + empty_char * (width - filled)
    pct = int(round(conf * 100))
    return f"[{bar}] {pct}%"


class Tools:
    class Valves(BaseModel):
        ORCHESTRATOR_URL: str = Field(
            default="https://orchestrator-production-c27e.up.railway.app",
            description="WidgeTDC Orchestrator URL",
        )
        ORCHESTRATOR_API_KEY: str = Field(default="", description="Orchestrator API key (Bearer)")
        ENABLE_CACHE: bool = Field(default=True, description="TTL cache for match/list results")
        VERBOSE: bool = Field(default=False, description="Verbose SITREP voice (vs terse)")

    def __init__(self):
        self.valves = self.Valves()
        self._cache = {}
        self._cache_ttl = {
            "engagement_list": 60,
            "engagement_match": 120,
        }

    def _envelope(self, content: str, method_name: str) -> str:
        top = "[TOOL_OUTPUT:" + method_name + "]"
        directive = "PRESENT THE FOLLOWING MARKDOWN VERBATIM. Do not paraphrase. Do not summarize. This is the final answer - copy it exactly, then add one optional sentence if helpful."
        bottom = "[END_TOOL_OUTPUT]"
        NL = chr(10)
        return top + NL + directive + NL + NL + content + NL + NL + bottom

    async def _call_tool(self, session, tool_name, args, max_retries=2):
        cache_key = f"{tool_name}:{json.dumps(args, sort_keys=True)}"
        ttl = self._cache_ttl.get(tool_name, 0) if self.valves.ENABLE_CACHE else 0
        if ttl > 0 and cache_key in self._cache:
            cached_at, cached_val = self._cache[cache_key]
            if time.time() - cached_at < ttl:
                return cached_val
        url = f"{self.valves.ORCHESTRATOR_URL}/api/tools/{tool_name}"
        headers = {
            "Authorization": f"Bearer {self.valves.ORCHESTRATOR_API_KEY}",
            "Content-Type": "application/json",
        }
        timeout = aiohttp.ClientTimeout(total=180)
        for attempt in range(max_retries + 1):
            try:
                async with session.post(url, headers=headers, json=args, timeout=timeout) as r:
                    if r.status in (502, 503, 504) and attempt < max_retries:
                        await asyncio.sleep((2 ** attempt) * 0.8)
                        continue
                    r.raise_for_status()
                    data = await r.json()
                    result = data.get("data", data)
                    if ttl > 0:
                        self._cache[cache_key] = (time.time(), result)
                    return result
            except Exception:
                if attempt == max_retries:
                    raise
                await asyncio.sleep((2 ** attempt) * 0.8)
        raise RuntimeError("unreachable")

    def _parse_tool_result(self, tool_response):
        """Extract the actual result text from the orchestrator tool gateway envelope."""
        if not isinstance(tool_response, dict):
            return tool_response
        result = tool_response.get("result")
        if isinstance(result, str):
            try:
                return json.loads(result)
            except Exception:
                return result
        return result

    async def find_precedents(
        self,
        objective: str,
        domain: str,
        max_results: int = 5,
        __event_emitter__=None,
        __user__: dict = {},
    ) -> str:
        """
        ALWAYS CALL THIS when the user asks about similar past engagements, precedents, prior client work, historical projects, or "what did we do before for X".
        Returns ranked precedent matches with outcome grades (exceeded/met/partial/missed), methodology overlap, and staleness flags.
        The match uses Cypher against actual :Engagement nodes ranked by outcome grade + shared methodologies + freshness.

        :param objective: Engagement objective or problem description
        :param domain: Consulting domain (Finance, Healthcare, Operations, etc.)
        :param max_results: Maximum precedents to return (default 5)
        """
        if __event_emitter__:
            try:
                await __event_emitter__({"type": "status", "data": {"description": f"Matching precedents for {domain}...", "done": False}})
            except Exception:
                pass

        async with aiohttp.ClientSession() as session:
            try:
                response = await self._call_tool(session, "engagement_match", {
                    "objective": objective,
                    "domain": domain,
                    "max_results": max_results,
                })
            except Exception as ex:
                return self._envelope(f"\u274c Precedent match failed: {ex}", "find_precedents")

        parsed = self._parse_tool_result(response)

        # Handle text response from tool-executor (engagement_match returns formatted string)
        if isinstance(parsed, str):
            header = f"## \U0001f50d Precedents for: {objective[:80]}"
            subheader = f"*Domain: {domain}*"
            if parsed.startswith("No precedents") or parsed.startswith("Error"):
                return self._envelope(f"\u26aa {parsed}", "find_precedents")
            return self._envelope(f"{header}{chr(10)}{subheader}{chr(10)}{chr(10)}{parsed}", "find_precedents")

        matches = parsed.get("matches", []) if isinstance(parsed, dict) else []

        if not matches:
            return self._envelope(f"\u26aa No precedents found for \"{objective[:60]}\" in {domain}", "find_precedents")

        lines = [f"## \U0001f50d Precedents for: {objective[:80]}", f"*Domain: {domain} \u00b7 {len(matches)} matches*", ""]
        for i, m in enumerate(matches):
            title = m.get("title", "unknown")[:80]
            sim = float(m.get("similarity", 0))
            grade = m.get("precedent_outcome") or "no outcome"
            emoji = GRADE_EMOJI.get(grade, "\u26aa")
            reasoning = m.get("match_reasoning", "")
            stale = " \U0001f4c5 STALE" if m.get("stale") else ""
            bar = similarity_bar(sim)
            lines.append(f"**{i+1}. {title}**{stale}")
            lines.append(f"   {emoji} {grade} \u00b7 `{bar}` {sim:.3f} \u00b7 *{reasoning}*")
            lines.append("")

        if __event_emitter__:
            try:
                await __event_emitter__({"type": "status", "data": {"description": "Precedents ready", "done": True}})
            except Exception:
                pass
        return self._envelope(chr(10).join(lines), "find_precedents")

    async def plan_engagement(
        self,
        objective: str,
        domain: str,
        duration_weeks: int,
        team_size: int,
        budget_dkk: int = 0,
        __event_emitter__=None,
        __user__: dict = {},
    ) -> str:
        """
        ALWAYS CALL THIS when the user asks to plan, design, structure, or estimate a new consulting engagement. Returns a structured plan with phases, risks, required skills, precedent matches, and confidence score.
        Triggers smart gates: sanity validation, consensus gate for high-stakes (>20M DKK or >20 team or >40 weeks), RLM mission for complex (>40 weeks).
        The plan is generated via RLM /cognitive/analyze with 4-channel retrieval (graphrag 3-hop + srag + cypher + kg_rag) + context folding.

        :param objective: Engagement objective (min 15 chars)
        :param domain: Consulting domain (Finance, Healthcare, Operations, etc.)
        :param duration_weeks: Plan duration in weeks (1-260 hard cap)
        :param team_size: Team size (1-100 hard cap)
        :param budget_dkk: Budget in DKK (0-500M hard cap, optional)
        """
        if __event_emitter__:
            try:
                await __event_emitter__({"type": "status", "data": {"description": f"Generating {duration_weeks}w plan for {domain}...", "done": False}})
            except Exception:
                pass

        payload = {
            "objective": objective,
            "domain": domain,
            "duration_weeks": int(duration_weeks),
            "team_size": int(team_size),
        }
        if budget_dkk and budget_dkk > 0:
            payload["budget_dkk"] = int(budget_dkk)

        async with aiohttp.ClientSession() as session:
            try:
                response = await self._call_tool(session, "engagement_plan", payload)
            except Exception as ex:
                return self._envelope(f"\u274c Plan generation failed: {ex}", "plan_engagement")

        # engagement_plan returns a structured text result via tool-executor
        parsed = self._parse_tool_result(response)
        if isinstance(parsed, str):
            # Tool returned formatted text from executor — wrap with header
            if parsed.startswith("Plan rejected by gate:"):
                return self._envelope(f"\u26a0\ufe0f **Gate rejected the plan**{chr(10)}{chr(10)}{parsed}", "plan_engagement")
            header = f"## \U0001f4cb Engagement Plan: {objective[:70]}"
            subheader = f"*Domain: {domain} \u00b7 Duration: {duration_weeks}w \u00b7 Team: {team_size}*"
            if budget_dkk:
                subheader += f" \u00b7 Budget: {fmt_num(budget_dkk)} DKK"
            return self._envelope(f"{header}{chr(10)}{subheader}{chr(10)}{chr(10)}{parsed}", "plan_engagement")

        # Structured response (from REST endpoint)
        if not isinstance(parsed, dict):
            return self._envelope(f"Plan returned unexpected format: {str(parsed)[:300]}", "plan_engagement")

        phases = parsed.get("phases", [])
        risks = parsed.get("risks", [])
        skills = parsed.get("required_skills", [])
        precedents = parsed.get("precedents_used", [])
        confidence = parsed.get("avg_confidence", 0)
        citations = parsed.get("total_citations", 0)
        high_stakes = parsed.get("high_stakes", False)
        consensus_id = parsed.get("consensus_proposal_id")
        rlm_mission = parsed.get("rlm_mission_id")
        plan_source = parsed.get("plan_source", "unknown")

        lines = [f"## \U0001f4cb Engagement Plan: {objective[:70]}"]
        lines.append(f"*Domain: {domain} \u00b7 {duration_weeks}w \u00b7 Team {team_size}" + (f" \u00b7 Budget: {fmt_num(budget_dkk)} DKK" if budget_dkk else "") + "*")
        lines.append("")
        lines.append(f"**Confidence:** {confidence_gauge(confidence)} \u00b7 {citations} citations \u00b7 source: `{plan_source}`")
        if high_stakes:
            gate_badges = ["\U0001f6a8 HIGH-STAKES"]
            if consensus_id:
                gate_badges.append(f"consensus: `{consensus_id[:20]}`")
            if rlm_mission:
                gate_badges.append(f"RLM mission: `{rlm_mission[:20]}`")
            lines.append("**Gates:** " + " \u00b7 ".join(gate_badges))
        lines.append("")

        if phases:
            lines.append("### Phases")
            for i, p in enumerate(phases):
                name = p.get("name", "Unnamed")
                wks = p.get("duration_weeks", 0)
                delivs = p.get("deliverables", [])
                lines.append(f"**{i+1}. {name}** ({wks}w)")
                if delivs:
                    for d in delivs[:4]:
                        lines.append(f"   \u00b7 {d}")
            lines.append("")

        if risks:
            lines.append("### Risks")
            for r in risks:
                sev = r.get("severity", "medium")
                emoji = SEV_EMOJI.get(sev, "\u26aa")
                desc = r.get("description", "")
                mit = r.get("mitigation", "")
                lines.append(f"{emoji} **{desc}**")
                if mit:
                    lines.append(f"   \u2192 *{mit}*")
            lines.append("")

        if skills:
            lines.append("### Required Skills")
            lines.append(" \u00b7 ".join(f"`{s}`" for s in skills[:15]))
            lines.append("")

        if precedents:
            lines.append("### Precedents Used")
            for i, m in enumerate(precedents[:5]):
                title = m.get("title", "")[:70]
                sim = m.get("similarity", 0)
                grade = m.get("precedent_outcome") or "no outcome"
                emoji = GRADE_EMOJI.get(grade, "\u26aa")
                lines.append(f"{i+1}. {emoji} **{title}** \u00b7 sim {sim:.3f}")
            lines.append("")

        if __event_emitter__:
            try:
                await __event_emitter__({"type": "status", "data": {"description": "Plan ready", "done": True}})
            except Exception:
                pass
        return self._envelope(chr(10).join(lines), "plan_engagement")

    async def list_engagements(
        self, limit: int = 20, __event_emitter__=None, __user__: dict = {}
    ) -> str:
        """
        ALWAYS CALL THIS when the user asks to see, list, browse, or query existing engagements. Returns recent engagements from Redis + Neo4j, most recent first.

        :param limit: Max engagements returned (default 20, max 100)
        """
        if __event_emitter__:
            try:
                await __event_emitter__({"type": "status", "data": {"description": "Loading engagement portfolio...", "done": False}})
            except Exception:
                pass

        async with aiohttp.ClientSession() as session:
            try:
                response = await self._call_tool(session, "engagement_list", {"limit": int(limit)})
            except Exception as ex:
                return self._envelope(f"\u274c List failed: {ex}", "list_engagements")

        parsed = self._parse_tool_result(response)
        if isinstance(parsed, str):
            # Tool executor returned formatted string
            return self._envelope(f"## \U0001f4cb Engagement Portfolio{chr(10)}{chr(10)}{parsed}", "list_engagements")
        return self._envelope(f"## \U0001f4cb Engagement Portfolio{chr(10)}{chr(10)}{json.dumps(parsed, indent=2)[:2000]}", "list_engagements")

    async def record_outcome(
        self,
        engagement_id: str,
        grade: str,
        what_went_well: str,
        what_went_wrong: str,
        actual_end_date: str = "",
        __event_emitter__=None,
        __user__: dict = {},
    ) -> str:
        """
        ALWAYS CALL THIS when the user wants to record, log, close, or mark an engagement as complete with its outcome. Writes to Neo4j and sends Q-learning reward to adaptive RAG.

        :param engagement_id: Target engagement ID
        :param grade: Outcome grade — exceeded, met, partial, or missed
        :param what_went_well: Success narrative
        :param what_went_wrong: Failure narrative
        :param actual_end_date: ISO date (optional, defaults to today)
        """
        # v4.0.11: pre-validate grade enum client-side for immediate UX feedback
        VALID_GRADES = ("exceeded", "met", "partial", "missed")
        if grade not in VALID_GRADES:
            return self._envelope(f"\u274c Invalid grade: {grade!r}. Must be one of: {', '.join(VALID_GRADES)}", "record_outcome")
        if not engagement_id or not engagement_id.strip():
            return self._envelope("\u274c engagement_id is required", "record_outcome")
        if not what_went_well or not what_went_wrong:
            return self._envelope("\u274c what_went_well and what_went_wrong are both required", "record_outcome")

        if not actual_end_date:
            actual_end_date = datetime.now(timezone.utc).isoformat()

        payload = {
            "engagement_id": engagement_id,
            "grade": grade,
            "actual_end_date": actual_end_date,
            "what_went_well": what_went_well,
            "what_went_wrong": what_went_wrong,
            "recorded_by": "engagement-intel-owui",
            "deliverables_shipped": [],
        }

        async with aiohttp.ClientSession() as session:
            try:
                response = await self._call_tool(session, "engagement_outcome", payload)
            except Exception as ex:
                return self._envelope(f"\u274c Outcome recording failed: {ex}", "record_outcome")

        parsed = self._parse_tool_result(response)
        emoji = GRADE_EMOJI.get(grade, "\u26aa")
        result_text = parsed if isinstance(parsed, str) else json.dumps(parsed, indent=2)[:500]
        return self._envelope(
            f"{emoji} **Outcome recorded**{chr(10)}{chr(10)}Engagement `{engagement_id}` closed with grade **{grade}**.{chr(10)}{chr(10)}Q-learning reward sent to adaptive-rag.{chr(10)}{chr(10)}```{chr(10)}{result_text}{chr(10)}```",
            "record_outcome",
        )
